const gitIgnorePath = $.path(Deno.cwd()).join(".gitignore");
try {
    const gitIgnore = Deno.readTextFileSync(gitIgnorePath);
    input.toBeIgnored = gitIgnore.split("\n").map((glob) => std.globToRegExp(glob));
} catch (_e) {
    // probably no .gitignore file
    input.toBeIgnored = [];
}

